from openai_agents import MultiAgentWorkflow
from vex_sdk import VexTracer

class LegalWorkflow(MultiAgentWorkflow):
    def __init__(self):
        self.tracer = VexTracer(
            dataset="legal_case_123",
            tags=["privileged", "court_filing"]
        )
        self.research_agent = Agent(...)
        self.draft_agent = Agent(
            input_guardrail=self.tracer.validate_handoff
        )

    def run(self, query):
        result = self.research_agent.run(query)
        traced_result = self.tracer.record_handoff(result)
        return self.draft_agent.run(traced_result.content)

from vex_sdk import VexGuardrail

privilege_guard = VexGuardrail(
    name="attorney_client_privilege",
    policy={
        "block": [
            "ssn_pattern",
            "client_name_leak",
            "strategy_confidential",
            "privileged_communication"
        ],
        "require": [
            "attorney_review_required",
            "ai_generated_disclaimer"
        ]
    }
)

class CompliantLegalAgent(Agent):
    def __init__(self):
        super().__init__(
            output_guardrail=privilege_guard
        )

    def process(self, input):
        response = self._generate(input)
        validated = self.output_guardrail.check(response)
        if not validated.compliant:
            raise ComplianceError(validated.violations)
